sql:
SELECT sequences.sequence_id, sequences.sequence_name, expression_levels.expression_value, expression_levels.expression_unit
FROM sequences
INNER JOIN expression_levels ON sequences.sequence_id = expression_levels.sequence_id;

SELECT annotation_value, COUNT(sequence_id) as count_sequences
FROM sequence_annotations
GROUP BY annotation_value;

external_knowledge:
; High expression levels refer to expression values greater than 10; 
; Meaningful samples refer to samples with non-empty or non-whitespace sample types; 
; Multiple distinct annotations refer to more than one unique annotation ID associated with each sequence.

sql:
SELECT samples.sample_name, samples.sample_type, sequence_samples.relationship_type
FROM samples
JOIN sequence_samples ON samples.sample_id = sequence_samples.sample_id;

SELECT AVG(sequence_count) 
FROM (
    SELECT sample_id, COUNT(sequence_id) AS sequence_count 
    FROM sequence_samples 
    GROUP BY sample_id
);
